         if !self.agents.contains_key(&base) {
             return Ok(base);
         }

         let mut number = 2;
         loop {
             let candidate = AgentId::new(format!("linearize-{number}")).map_err(CliError::Agent)?;
             if !self.agents.contains_key(&candidate) {
                 return Ok(candidate);
             }
             number += 1;
         }
