+#[derive(Clone, Copy, Debug, Eq, PartialEq)]
+pub(crate) struct AgentBackendCommand<'a> {
+    pub name: &'a str,
+    pub arguments: &'a str,
+}
+
+pub(crate) fn agent_backend_command(message: &str) -> Option<AgentBackendCommand<'_>> {
+    let rest = message.trim().strip_prefix('/')?;
+    let name_end = rest.find(char::is_whitespace).unwrap_or(rest.len());
+    if name_end == 0 {
+        return None;
+    }
+    Some(AgentBackendCommand {
+        name: &rest[..name_end],
+        arguments: rest[name_end..].trim_start(),
+    })
+}
