589	    fn process_agent_reply_streaming_result(
590	        &mut self,
591	        agent_id: &AgentId,
592	        feature: &str,
593	        reply: String,
594	        stream: &mut dyn FnMut(&AgentId, AgentStreamEvent),
595	    ) -> Result<ProcessedAgentReply, CliError> {
596	        let mut text = reply.clone();
597	        let mut final_reply = reply.clone();
598	        let mut pending = VecDeque::from([AgentFollowUp {
599	            agent_id: agent_id.clone(),
600	            text: reply,
601	        }]);
602	        let mut rounds = 0;
603	
604	        while let Some(current) = pending.pop_front() {
605	            if current.agent_id == *agent_id {
606	                final_reply = current.text.clone();
607	            }
608	            if rounds >= self.max_review_rounds {
609	                let message = format!(
610	                    "agent did not converge after {} orchestrator rounds",
611	                    self.max_review_rounds
612	                );
613	                text.push_str("\n\norchestrator:\n");
614	                text.push_str(&message);
615	                final_reply = message;
616	                break;
617	            }
618	            rounds += 1;
619	
620	            let current_feature =
621	                self.agents
622	                    .get(&current.agent_id)
623	                    .cloned()
624	                    .unwrap_or_else(|| {
625	                        if current.agent_id == *agent_id {
626	                            feature.to_string()
627	                        } else {
628	                            "user-agent".to_string()
629	                        }
630	                    });
631	            let run = {
632	                let backend = self
633	                    .backend
634	                    .as_mut()
635	                    .expect("command chat backend is present");
636	                handle_agent_directives_streaming(
637	                    backend,
638	                    DirectiveServices {
639	                        locks: &self.locks,
640	                        file_reads: &self.file_reads,
641	                        command_changes: &self.command_changes,
642	                        command_policy: &self.command_policy,
643	                        locked_command_timeout: self.locked_command_timeout,
644	                    },
645	                    &current.agent_id,
646	                    &current_feature,
647	                    &current.text,
648	                    stream,
649	                )?
650	            };
651	
652	            append_orchestrator_events(&mut text, &run.events);
653	            append_follow_ups(&mut text, &run.follow_up_replies);
654	
655	            if run.completed && current.agent_id == *agent_id {
656	                break;
657	            }
658	
659	            for follow_up in run.follow_up_replies {
660	                if !follow_up.text.is_empty() {
661	                    pending.push_back(follow_up);
662	                }
663	            }
664	        }
665	
666	        Ok(ProcessedAgentReply {
667	            transcript: text,
668	            final_reply,
669	        })
670	    }
