561	    let normalized_paths = response
562	        .snapshots
563	        .iter()
564	        .map(|snapshot| snapshot.path.clone())
565	        .collect::<Vec<_>>();
566	    let unavailable_paths = response
567	        .failures
568	        .iter()
569	        .map(|failure| failure.path.clone())
570	        .collect::<Vec<_>>();
571	    let prompt = render_file_read_response(&response.snapshots, &response.failures);
572	    let mut sink = |event| stream(agent_id, event);
573	    let reply = backend.send_streaming(agent_id, &prompt, &mut sink)?;
574	    services
575	        .file_reads
576	        .record_snapshots(agent_id, &response.snapshots);
577	    run.follow_up_replies
578	        .push(follow_up(agent_id.clone(), reply));
579	    if !normalized_paths.is_empty() {
580	        run.events.push(OrchestratorEvent::FileTextSent {
581	            agent_id: agent_id.clone(),
582	            paths: normalized_paths,
583	        });
584	    }
585	    if !unavailable_paths.is_empty() {
586	        run.events.push(OrchestratorEvent::FileTextUnavailable {
587	            agent_id: agent_id.clone(),
588	            paths: unavailable_paths,
589	            diagnostic: render_file_read_failures(&response.failures),
